<template>
  <div>
    <h1>Staff Training Quiz</h1>

    <div v-if="!testStarted">
      <p>Test yourself on the helpdesk responses.</p>
      <button class="ui button primary" @click="startTest" :disabled="issues.length === 0">
        Start Quiz
      </button>
      <div v-if="issues.length === 0" class="ui negative message">
        You need to add some helpdesk issues before you can start the training quiz!
      </div>
    </div>

    <div v-else-if="currentIssue">
      <div class="ui segment">
        <h3>What is the correct response for this issue?</h3>
        <h2 class="ui header teal">{{ currentIssue.issueCode }}</h2>
        <div class="ui labeled input fluid" style="margin-top: 20px;">
          <div class="ui label"><i class="keyboard icon"></i> Response</div>
          <input type="text" placeholder="Type the standard response..." v-model="userAnswer" @keyup.enter="checkAnswer" />
        </div>
        <button class="ui button positive" style="margin-top: 15px;" @click="checkAnswer">Check</button>
      </div>
      
      <div v-if="feedbackMessage" :class="['ui', 'message', isCorrect ? 'positive' : 'negative']">
        <div class="header">{{ isCorrect ? 'Correct!' : 'Incorrect!' }}</div>
        <p>{{ feedbackMessage }}</p>
        <button v-if="isCorrect" class="ui button primary" @click="nextQuestion">Next Question</button>
        <button v-else class="ui button" @click="userAnswer=''">Try Again</button>
      </div>
    </div>
  </div>
</template>

<script>
import { api } from '../helpers/helpers';

export default {
  name: 'test',
  data() {
    return {
      issues: [],
      testStarted: false,
      currentIssue: null,
      userAnswer: '',
      feedbackMessage: '',
      isCorrect: false
    };
  },
  methods: {
    startTest() {
      if (this.issues.length > 0) {
        this.testStarted = true;
        this.nextQuestion();
      }
    },
    nextQuestion() {
      // Pick a random issue
      const randomIndex = Math.floor(Math.random() * this.issues.length);
      this.currentIssue = this.issues[randomIndex];
      this.userAnswer = '';
      this.feedbackMessage = '';
      this.isCorrect = false;
    },
    checkAnswer() {
      if (this.userAnswer.trim().toLowerCase() === this.currentIssue.response.trim().toLowerCase()) {
        this.isCorrect = true;
        this.feedbackMessage = `Great job! The correct response for ${this.currentIssue.issueCode} is indeed "${this.currentIssue.response}".`;
      } else {
        this.isCorrect = false;
        this.feedbackMessage = `Wait, that's not quite right. Try again.`;
      }
    }
  },
  async mounted() {
    this.issues = await api.getIssues();
  }
};
</script>
